/* HealingMart Calculator PC Share v1.4.0
 * Based on the HealingMart inline SNS share button set.
 */
(function (w, d) {
  "use strict";

  var KAKAO_JS_KEY = "a6897bdb5b7785b0ffbe542d81886b93";
  var KAKAO_SDK = "https://t1.kakaocdn.net/kakao_js_sdk/2.8.1/kakao.min.js";
  var kakaoPromise = null;

  function ensureKakao() {
    if (w.Kakao) {
      try { if (!w.Kakao.isInitialized()) w.Kakao.init(KAKAO_JS_KEY); } catch (_) {}
      return Promise.resolve(w.Kakao);
    }
    if (kakaoPromise) return kakaoPromise;
    kakaoPromise = new Promise(function (resolve) {
      var s = d.createElement("script");
      s.src = KAKAO_SDK;
      s.onload = function () {
        try { if (w.Kakao && !w.Kakao.isInitialized()) w.Kakao.init(KAKAO_JS_KEY); } catch (_) {}
        resolve(w.Kakao || null);
      };
      s.onerror = function () { resolve(null); };
      d.head.appendChild(s);
    });
    return kakaoPromise;
  }

  function getShareData(root) {
    var meta = d.querySelector('meta[name="description"]');
    var og = d.querySelector('meta[property="og:image"]');
    var label = root.querySelector('.hm-calc-result-label');
    var value = root.querySelector('.hm-calc-result-value');
    var resultText = label && value && !value.closest('[hidden]') ? label.textContent.trim() + ': ' + value.textContent.trim() : '';
    return {
      url: w.location.href,
      title: d.title || '힐링편의점 계산기',
      desc: meta ? meta.content : '힐링편의점의 유용한 계산기를 확인해보세요!',
      img: og ? og.content : '',
      resultText: resultText
    };
  }

  function open(url) {
    w.open(url, '_blank', 'noopener,noreferrer,width=720,height=620');
  }

  function toast(root, message) {
    var el = root.querySelector('.hm-calc-share-toast');
    if (!el) {
      el = d.createElement('div');
      el.className = 'hm-calc-share-toast';
      el.setAttribute('role', 'status');
      el.setAttribute('aria-live', 'polite');
      root.appendChild(el);
    }
    el.textContent = message;
    el.classList.add('is-show');
    clearTimeout(el._timer);
    el._timer = setTimeout(function () { el.classList.remove('is-show'); }, 1800);
  }

  async function copyText(text) {
    if (navigator.clipboard && navigator.clipboard.writeText) return navigator.clipboard.writeText(text);
    var ta = d.createElement('textarea');
    ta.value = text;
    ta.style.position = 'fixed';
    ta.style.opacity = '0';
    d.body.appendChild(ta);
    ta.select();
    d.execCommand('copy');
    ta.remove();
  }

  async function fallbackShare(root, data) {
    try {
      if (navigator.share) {
        await navigator.share({title:data.title, text:data.resultText || data.desc, url:data.url});
        return;
      }
    } catch (err) {
      if (err && err.name === 'AbortError') return;
    }
    try {
      await copyText((data.resultText ? data.resultText + '\n' : '') + data.url);
      toast(root, '링크가 복사되었습니다.');
    } catch (_) { toast(root, '공유 기능을 사용할 수 없습니다.'); }
  }

  function mount(root) {
    if (!root || root.dataset.hmCalcShareMounted === 'true') return;
    root.dataset.hmCalcShareMounted = 'true';

    var wrap = d.createElement('section');
    wrap.className = 'hm-calc-share-inline hm-calc-pc-share';
    wrap.setAttribute('aria-label', '계산기 SNS 공유');
    wrap.innerHTML = '\
      <div class="hm-calc-share-title">도움이 되셨다면 공유 부탁드립니다 😊</div>\
      <div class="hm-calc-share-buttons">\
        <button type="button" class="hm-calc-share-btn kakao" data-share="kakao" title="카카오톡"><svg fill="#3C1E1E" viewBox="0 0 24 24"><path d="M12 3C6.5 3 2 6.6 2 11c0 2.9 1.9 5.4 4.7 6.8-.2.7-.7 2.6-.8 3-.1.5.2.5.4.4.2-.1 2.6-1.8 3.7-2.5.7.1 1.3.2 2 .2 5.5 0 10-3.6 10-8S17.5 3 12 3z"/></svg></button>\
        <button type="button" class="hm-calc-share-btn naver" data-share="naver" title="네이버"><svg fill="#fff" viewBox="0 0 24 24"><path d="M16.3 12.6L7.7 0H0v24h7.7V11.4L16.3 24H24V0h-7.7v12.6z"/></svg></button>\
        <button type="button" class="hm-calc-share-btn facebook" data-share="facebook" title="페이스북"><svg fill="#fff" viewBox="0 0 24 24"><path d="M24 12c0-6.6-5.4-12-12-12S0 5.4 0 12c0 6 4.4 11 10.1 11.9v-8.4H7.1V12h3.1V9.4c0-3 1.8-4.7 4.5-4.7 1.3 0 2.7.2 2.7.2v2.9h-1.5c-1.5 0-2 .9-2 1.9V12h3.3l-.5 3.5h-2.8v8.4C19.6 23 24 18 24 12z"/></svg></button>\
        <button type="button" class="hm-calc-share-btn x" data-share="x" title="X (트위터)"><svg fill="#fff" viewBox="0 0 24 24"><path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-5.214-6.817L4.99 21.75H1.68l7.73-8.835L1.254 2.25H8.08l4.713 6.231zm-1.161 17.52h1.833L7.084 4.126H5.117z"/></svg></button>\
        <button type="button" class="hm-calc-share-btn threads" data-share="threads" title="Threads"><svg fill="#fff" viewBox="0 0 192 192"><path d="M141.537 88.9883C140.71 88.5919 139.87 88.2104 139.019 87.8451C137.537 60.5382 122.616 44.905 97.5619 44.745C97.4484 44.7443 97.3355 44.7443 97.222 44.7443C82.2364 44.7443 69.7731 51.1409 62.102 62.7807L75.881 72.2328C81.6116 63.5383 90.6052 61.6848 97.2286 61.6848C97.3051 61.6848 97.3819 61.6848 97.4576 61.6855C105.707 61.7381 111.932 64.1366 115.961 68.814C118.893 72.2193 120.854 76.925 121.825 82.8638C114.511 81.6207 106.601 81.2385 98.145 81.7233C74.3247 83.0954 59.0111 96.9879 60.0396 116.292C60.5615 126.084 65.4397 134.508 73.775 140.011C80.8224 144.663 89.899 146.938 99.3323 146.423C111.79 145.74 121.563 140.987 128.381 132.296C133.559 125.696 136.834 117.143 138.28 106.366C144.217 109.949 148.617 114.664 151.047 120.332C155.179 129.967 155.42 145.8 142.501 158.708C131.182 170.016 117.576 174.908 97.0135 175.059C74.2042 174.89 56.9538 167.575 45.7381 153.317C35.2355 139.966 29.8077 120.682 29.6052 96C29.8077 71.3178 35.2355 52.0336 45.7381 38.6827C56.9538 24.4249 74.2039 17.11 97.0132 16.9405C119.988 17.1113 137.539 24.4614 149.184 38.788C154.894 45.8136 159.199 54.6488 162.037 64.9503L178.184 60.6422C174.744 47.9622 169.331 37.0357 161.965 27.974C147.036 9.60668 125.202 0.195148 97.0695 0H96.9569C68.8816 0.19447 47.2921 9.6418 32.7883 28.0793C19.8819 44.4864 13.2244 67.3157 13.0007 95.9325L13 96L13.0007 96.0675C13.2244 124.684 19.8819 147.514 32.7883 163.921C47.2921 182.358 68.8816 191.806 96.9569 192H97.0695C122.03 191.827 139.624 185.292 154.118 170.811C173.081 151.866 172.51 128.119 166.26 113.541C161.776 103.087 153.227 94.5962 141.537 88.9883ZM98.4405 129.507C88.0005 130.095 77.1544 125.409 76.6196 115.372C76.2232 107.93 81.9158 99.626 99.0812 98.6368C101.047 98.5234 102.976 98.468 104.871 98.468C111.106 98.468 116.939 99.0737 122.242 100.233C120.264 124.935 108.662 128.946 98.4405 129.507Z"/></svg></button>\
        <button type="button" class="hm-calc-share-btn more" data-share="more" title="더보기"><svg fill="#fff" viewBox="0 0 24 24"><circle cx="5" cy="12" r="2"/><circle cx="12" cy="12" r="2"/><circle cx="19" cy="12" r="2"/></svg></button>\
      </div>\
      <div class="hm-calc-share-more" hidden>\
        <button type="button" class="hm-calc-share-btn copy" data-share="copy" title="링크 복사"><svg fill="#fff" viewBox="0 0 24 24"><path d="M16 1H4c-1.1 0-2 .9-2 2v14h2V3h12V1zm3 4H8c-1.1 0-2 .9-2 2v14c0 1.1.9 2 2 2h11c1.1 0 2-.9 2-2V7c0-1.1-.9-2-2-2zm0 16H8V7h11v14z"/></svg></button>\
        <button type="button" class="hm-calc-share-btn band" data-share="band" title="네이버 밴드"><svg fill="#fff" viewBox="0 0 24 24"><path d="M12 2C6.5 2 2 6.5 2 12s4.5 10 10 10 10-4.5 10-10S17.5 2 12 2zm5 12h-4v4h-2v-4H7v-2h4V8h2v4h4v2z"/></svg></button>\
        <button type="button" class="hm-calc-share-btn telegram" data-share="telegram" title="텔레그램"><svg fill="#fff" viewBox="0 0 24 24"><path d="M9.78 18.65l.28-4.23 7.68-6.92c.34-.31-.07-.46-.52-.19L7.74 13.3 3.64 12c-.88-.25-.89-.86.2-1.3l15.97-6.16c.73-.33 1.43.18 1.15 1.3l-2.72 12.81c-.19.91-.74 1.13-1.5.71L12.6 16.3l-1.99 1.93c-.23.23-.42.42-.83.42z"/></svg></button>\
      </div>';
    root.appendChild(wrap);

    wrap.addEventListener('click', async function (event) {
      var btn = event.target.closest('[data-share]');
      if (!btn) return;
      var action = btn.dataset.share;
      var data = getShareData(root);
      if (action === 'more') {
        var more = wrap.querySelector('.hm-calc-share-more');
        var show = more.hidden;
        more.hidden = !show;
        return;
      }
      if (action === 'kakao') {
        var kakao = await ensureKakao();
        try {
          if (kakao && kakao.Share && kakao.isInitialized()) {
            kakao.Share.sendDefault({
              objectType: 'feed',
              content: {
                title: data.title,
                description: data.resultText || data.desc,
                imageUrl: data.img || 'https://www.healing-mart.com/favicon.ico',
                link: {mobileWebUrl:data.url, webUrl:data.url}
              }
            });
          } else await fallbackShare(root, data);
        } catch (_) { await fallbackShare(root, data); }
      } else if (action === 'naver') {
        open('https://share.naver.com/web/shareView?url=' + encodeURIComponent(data.url) + '&title=' + encodeURIComponent(data.title));
      } else if (action === 'facebook') {
        open('https://www.facebook.com/sharer/sharer.php?u=' + encodeURIComponent(data.url));
      } else if (action === 'x') {
        open('https://twitter.com/intent/tweet?url=' + encodeURIComponent(data.url) + '&text=' + encodeURIComponent(data.title));
      } else if (action === 'threads') {
        open('https://www.threads.net/intent/post?text=' + encodeURIComponent(data.title + '\n' + data.url));
      } else if (action === 'band') {
        open('https://band.us/plugin/share?body=' + encodeURIComponent(data.title + '\r\n' + data.url));
      } else if (action === 'telegram') {
        open('https://t.me/share/url?url=' + encodeURIComponent(data.url) + '&text=' + encodeURIComponent(data.title));
      } else if (action === 'copy') {
        try { await copyText(data.url); toast(root, '링크가 복사되었습니다!'); }
        catch (_) { toast(root, '복사에 실패했습니다.'); }
      }
    });
  }

  w.HM_CALC_SHARE = {mount:mount};
})(window, document);
